# Script para Gerar APK - BarberMove# Data: 03/02/2026Write-Host ""Write-Host "============================================================" -ForegroundColor CyanWrite-Host "     GERAR APK - BarberMove v1.0                           " -ForegroundColor CyanWrite-Host "============================================================" -ForegroundColor CyanWrite-Host ""$ErrorActionPreference = "Stop"$startTime = Get-Datetry {    Set-Location -Path "C:\projeto_barbearia\barbermove"        Write-Host "[1/4] Instalando dependencias..." -ForegroundColor Yellow    npm install --silent    Write-Host "      OK - Dependencias instaladas!" -ForegroundColor Green    Write-Host ""        Write-Host "[2/4] Gerando build de producao..." -ForegroundColor Yellow    npm run build    Write-Host "      OK - Build gerado em dist/" -ForegroundColor Green    Write-Host ""        Write-Host "[3/4] Sincronizando com Capacitor Android..." -ForegroundColor Yellow    npx cap sync android --inline    Write-Host "      OK - Sincronizacao concluida!" -ForegroundColor Green    Write-Host ""        Write-Host "[4/4] Compilando APK Android..." -ForegroundColor Yellow    Write-Host "      Aguarde... Isso pode levar alguns minutos..." -ForegroundColor Cyan        Set-Location android    .\gradlew.bat assembleDebug --quiet    Set-Location ..        Write-Host "      OK - APK compilado com sucesso!" -ForegroundColor Green    Write-Host ""        $timestamp = Get-Date -Format "yyyyMMdd_HHmmss"    $apkSource = "android\app\build\outputs\apk\debug\app-debug.apk"    $apkDest = "..\BarberMove_$timestamp.apk"        if (Test-Path $apkSource) {        Copy-Item $apkSource $apkDest -Force                $apkSize = (Get-Item $apkSource).Length / 1MB        $apkSizeMB = [math]::Round($apkSize, 2)                Write-Host "============================================================" -ForegroundColor Green        Write-Host "              APK GERADO COM SUCESSO!                      " -ForegroundColor Green        Write-Host "============================================================" -ForegroundColor Green        Write-Host ""        Write-Host "Localizacao do APK:" -ForegroundColor Cyan        Write-Host "   $apkDest" -ForegroundColor White        Write-Host "   Tamanho: $apkSizeMB MB" -ForegroundColor White        Write-Host ""        Write-Host "COMO INSTALAR NO CELULAR:" -ForegroundColor Yellow        Write-Host "   1. Transfira o APK para o celular (USB ou email)" -ForegroundColor White        Write-Host "   2. Abra o arquivo no celular" -ForegroundColor White        Write-Host "   3. Permita 'Instalar de fontes desconhecidas'" -ForegroundColor White        Write-Host "   4. Instale o app" -ForegroundColor White        Write-Host ""        Write-Host "IMPORTANTE:" -ForegroundColor Yellow        Write-Host "   - Este e um APK de DEBUG (desenvolvimento)" -ForegroundColor White        Write-Host "   - Para producao/Google Play, gere APK assinado" -ForegroundColor White        Write-Host "   - Veja instrucoes em: GUIA_ANDROID_IOS.md" -ForegroundColor White        Write-Host ""                $apkPath = Resolve-Path $apkDest        Write-Host "Abrindo pasta do APK..." -ForegroundColor Cyan        explorer.exe /select,"$apkPath"            } else {        Write-Host "ERRO: APK nao encontrado em $apkSource" -ForegroundColor Red        exit 1    }        $endTime = Get-Date    $duration = ($endTime - $startTime).TotalSeconds    $durationFormatted = [math]::Round($duration, 0)        Write-Host "Tempo total: $durationFormatted segundos" -ForegroundColor Cyan    Write-Host ""    } catch {    Write-Host ""    Write-Host "============================================================" -ForegroundColor Red    Write-Host "                  ERRO NO BUILD                            " -ForegroundColor Red    Write-Host "============================================================" -ForegroundColor Red    Write-Host ""    Write-Host "Possiveis solucoes:" -ForegroundColor Yellow    Write-Host "   1. Verifique se o Android SDK esta instalado" -ForegroundColor White    Write-Host "   2. Execute: .\setup_android_sdk.ps1" -ForegroundColor White    Write-Host "   3. Verifique a conexao com internet" -ForegroundColor White    Write-Host "   4. Tente executar novamente" -ForegroundColor White    Write-Host ""    Write-Host "Erro detalhado:" -ForegroundColor Red    Write-Host $_.Exception.Message -ForegroundColor White    Write-Host ""    exit 1} finally {    Set-Location "C:\projeto_barbearia"}